+template <int N, typename T>
+void Scalar<N, T>::operator=(T value) {
+// clang-format off
+#pragma HLS inline
+    // clang-format on
+    for (int k = 0; k < N; k++) {
+// clang-format off
+#pragma HLS unroll
+        // clang-format on
+        val[k] = value;
+    }
+}
+
