+Scalar<N, T> Scalar<N, T>::operator+(T value) {
+// clang-format off
+#pragma HLS inline
+    // clang-format on
+    Scalar<N, T> res;
+    for (int k = 0; k < N; k++) {
+// clang-format off
+#pragma HLS unroll
+        // clang-format on
+        res.val[k] = val[k] + value;
+    }
+    return res;
+}
