+inline Mat<T, ROWS, COLS, NPC, XFCVDEPTH>::Mat(const Mat& src) {
+    init(src.rows, src.cols);
+
+//	for(int i =0; i< (rows*(cols>>(XF_BITSHIFT(NPC))));++i){
+#ifndef __SYNTHESIS__
+    for (int i = 0; i < (rows * ((cols + NPC - 1) >> XF_BITSHIFT(NPC))); ++i) {
+        data[i] = src.data[i];
+    }
+#else
+//  for (int i = 0; i < (rows * ((cols + NPC - 1) >> XF_BITSHIFT(NPC))); ++i) {
+//      data[i] = src.read(i);
+//  }
+#endif
+}
