+inline float Mat<T, ROWS, COLS, NPPC, XFCVDEPTH>::read_float(int index) {
+    union int2float {
+        unsigned I;
+        float F;
+    };
+    int2float val;
+    val.I = read(index).to_uint();
+    return val.F;
