+/*
+ * Window content shift left
+ * Assumes new values will be placed in right column = COLS-1
+ */
+template <int ROWS, int COLS, typename T>
+void Window<ROWS, COLS, T>::shift_pixels_left() {
+// clang-format off
+    #pragma HLS inline
+// clang-format on
+
+#ifdef __DEBUG__
+    std::cout << "Window Elements: ";
+    window_print();
+    restore_val();
+#endif
+
+    XF_SIZE_T i, j;
+    for (i = 0; i < ROWS; i++) {
+// clang-format off
+        #pragma HLS unroll
+        // clang-format on
+        for (j = 0; j < COLS - 1; j++) {
+// clang-format off
+            #pragma HLS unroll
+            // clang-format on
+            val[i][j] = val[i][j + 1];
+        }
+    }
+
+#ifdef __DEBUG__
+    std::cout << "===  After " << __FUNCTION__ << ":  ===\n\n";
+    std::cout << "Window Elements Update: ";
+    window_print();
+    for (i = 0; i < ROWS; i++) {
+        for (j = 0; j < COLS; j++) {
+            if (j == COLS - 1)
+                assert(val_t[i][j] == val[i][j] && "*** window shift_pixels_left mismatch! ***");
+            else
+                assert(val_t[i][j + 1] == val[i][j] && "*** window shift_pixels_left mismatch! ***");
+        }
+    }
+#endif
+}
