+    XF_SIZE_T i, j;
+    for (i = 0; i < ROWS; i++) {
+// clang-format off
+        #pragma HLS unroll
+        // clang-format on
+        for (j = COLS - 1; j > 0; j--) {
+// clang-format off
+            #pragma HLS unroll
+            // clang-format on
+            val[i][j] = val[i][j - 1];
+        }
+    }
+
+#ifdef __DEBUG__
+    std::cout << "===  After " << __FUNCTION__ << ":  ===\n\n";
