+#ifdef __DEBUG__
+    std::cout << "===  After " << __FUNCTION__ << ":  ===\n\n";
+    std::cout << "Window Elements Update: ";
+    window_print();
+    XF_SIZE_T i, j;
+    for (i = 0; i < ROWS; i++) {
+        for (j = 0; j < COLS; j++) {
+            if (i != row && j != col) assert(val_t[i][j] == val[i][j] && "*** window insert_pixel mismatch! ***");
+        }
+    }
+    val_t[row][col] = value;
+    assert(val_t[row][col] == val[row][col] && "*** window insert_pixel mismatch! ***");
+#endif
