+    restore_val();
+#endif
+
+    XF_SIZE_T i;
+    for (i = 0; i < ROWS - 1; i++) {
+// clang-format off
+        #pragma HLS unroll
+        // clang-format on
+        val[i][col] = val[i + 1][col];
+    }
+
+#ifdef __DEBUG__
+    std::cout << "===  After " << __FUNCTION__ << ":  ===\n\n";
+    std::cout << "LineBuffer Elements Update in col=" << col << ":";
+    linebuffer_print(col);
+    XF_SIZE_T j;
+    for (i = 0; i < ROWS; i++) {
+        for (j = 0; j < COLS; j++) {
+            if (j == col)
+                if (i == ROWS - 1)
+                    assert(val_t[i][j] == val[i][j] && "*** window shift_pixels_up mismatch! ***");
