+    XF_SNAME(WORDWIDTH_DST) val_dst;
+    uchar_t result, p, q;
+    int STEP = XF_PIXELDEPTH(DEPTH) / PLANES;
+rowLoop:
+    for (i = 0; i < image_height; i++) {
+// clang-format off
+        #pragma HLS LOOP_TRIPCOUNT min=ROWS max=ROWS
