+
+    xf::cv::Mat<SRC_T, ROWS, COLS, NPC> hsvimg1(rows, cols);
+    xf::cv::Mat<SRC_T, ROWS, COLS, NPC> hsvimg2(rows, cols);
+    xf::cv::Mat<SRC_T, ROWS, COLS, NPC> hsvimg3(rows, cols);
