+PROCESS_LOOP_EXTRA:
+    for (int rem = 0; rem < rem_extra; rem++) {
+// clang-format off
+#pragma HLS LOOP_TRIPCOUNT min=REM_KEYPOINTS max=REM_KEYPOINTS
+        // clang-format on
