+static float xFBilateralFloatInv(float in_val) {
+    return float(1.0 / (in_val));
+}
+
+static float xFBilateralFloatMul(float in_val1, float in_val2) {
+    return float(in_val1 * in_val2);
+}
+static float xFBilateralExpf(float in_val) {
+    float result;
+    result = expf(in_val);
+    return result;
+}
