+            tp1 = 2;
+            tp2 = 3;
+            tp3 = 4;
+            mid = 5;
+            bottom1 = 6;
+            bottom2 = 0;
+            bottom3 = 1;
+        } else if (row_ind == 2) {
+            tp1 = 3;
+            tp2 = 4;
+            tp3 = 5;
+            mid = 6;
+            bottom1 = 0;
+            bottom2 = 1;
+            bottom3 = 2;
+        } else if (row_ind == 3) {
+            tp1 = 4;
+            tp2 = 5;
+            tp3 = 6;
+            mid = 0;
+            bottom1 = 1;
+            bottom2 = 2;
+            bottom3 = 3;
+        } else if (row_ind == 4) {
+            tp1 = 5;
+            tp2 = 6;
+            tp3 = 0;
+            mid = 1;
+            bottom1 = 2;
+            bottom2 = 3;
+            bottom3 = 4;
+        } else if (row_ind == 5) {
+            tp1 = 6;
+            tp2 = 0;
+            tp3 = 1;
+            mid = 2;
+            bottom1 = 3;
+            bottom2 = 4;
+            bottom3 = 5;
+        } else if (row_ind == 6) {
+            tp1 = 0;
+            tp2 = 1;
+            tp3 = 2;
+            mid = 3;
+            bottom1 = 4;
+            bottom2 = 5;
+            bottom3 = 6;
+        }
+
+        for (i = 0; i < 6; i++) {
+// clang-format off
+            #pragma HLS unroll
+            // clang-format on
+            src_buf1[i] = 0;
+            src_buf2[i] = 0;
+            src_buf3[i] = 0;
+            src_buf4[i] = 0;
+            src_buf5[i] = 0;
+            src_buf6[i] = 0;
+            src_buf7[i] = 0;
+        }
+        inter_val = 0;
+
+        ProcessBox7x7<SRC_T, ROWS, COLS, DEPTH, NPC, WORDWIDTH_SRC, WORDWIDTH_DST, WORDWIDTH_AP, TC>(
+            _src_mat, _dst_mat, buf, src_buf1, src_buf2, src_buf3, src_buf4, src_buf5, src_buf6, src_buf7,
+            GradientValues, inter_val, img_width, img_height, row_ind, shiftx, tp1, tp2, tp3, mid, bottom1, bottom2,
+            bottom3, row, rd_ind, wr_ind);
+
+        RightBorderBox7x7<SRC_T, ROWS, COLS, DEPTH, NPC, WORDWIDTH_SRC, WORDWIDTH_DST, WORDWIDTH_AP, TC>(
+            _dst_mat, src_buf1, src_buf2, src_buf3, src_buf4, src_buf5, src_buf6, src_buf7, GradientValues, inter_val,
+            img_width, img_height, row_ind, shiftx, row, wr_ind);
+        row_ind++;
+        if (row_ind == 7) {
+            row_ind = 0;
+        }
+    } // Row_Loop ends here
+} // end of function xFBoxFilter7x7
