+void xFDuplicate_rows(xf::cv::Mat<IN_T, ROWS, COLS, NPC>& _src_mat, // hls::stream< XF_SNAME(WORDWIDTH) > &_src_mat,
+                      xf::cv::Mat<IN_T, ROWS, COLS, NPC>& _src_mat1,
