+// clang-format off
+                    #pragma HLS UNROLL
+                    #pragma HLS LOOP_TRIPCOUNT min=WIN_SZ max=WIN_SZ
+                    // clang-format on
+                    if (col == img_width >> XF_BITSHIFT(NPC)) {
+                        src_buf[extract_px][col_warp + npc + (WIN_SZ >> 1)] =
