+                    } else {
+                        src_buf[extract_px][col_warp + npc + (WIN_SZ >> 1)] = src_buf_temp_copy[extract_px][col_warp];
+                    }
+                }
+            }
+
+            if (col == 0) {
+                for (int extract_px = 0; extract_px < WIN_SZ; extract_px++) {
+// clang-format off
+                    #pragma HLS LOOP_TRIPCOUNT min=WIN_SZ max=WIN_SZ
+                    // clang-format on
