+                                                                                  src_buf_temp_med_apply, WIN_SZ);
+                    xFSobelProcy5x5<NPC, DEPTH_SRC, DEPTH_DST, WIN_SZ, WIN_SZ_SQ>(OutputValues_percycle1,
