+                OutputValues1[applySobel] = OutputValues_percycle1[0];
+            }
+            if (col >= 1) {
+                shift_x = 0;
+                P0 = 0;
+                xfPackPixels<NPC, WORDWIDTH_DST, DEPTH_DST>(OutputValues, P0, 0, npc, shift_x);
+                shift_x = 0;
+                P1 = 0;
+                xfPackPixels<NPC, WORDWIDTH_DST, DEPTH_DST>(OutputValues1, P1, 0, npc, shift_x);
