+        } else {
+            for (int copy_buf_var = 0; copy_buf_var < WIN_SZ; copy_buf_var++) {
+// clang-format off
+                #pragma HLS LOOP_TRIPCOUNT min=WIN_SZ max=WIN_SZ
+                #pragma HLS UNROLL
+                // clang-format on
+                if ((row > (img_height - 1)) && (copy_buf_var > (win_size - 1 - (row - (img_height - 1))))) {
