+template <int DEPTH_IN, int DEPTH_PHASE, int DEPTH_OUT>
+XF_PTNAME(DEPTH_OUT)
+xFFindmax3x3(XF_PTNAME(DEPTH_IN) _i00,
+             XF_PTNAME(DEPTH_IN) _i01,
+             XF_PTNAME(DEPTH_IN) _i02,
+             XF_PTNAME(DEPTH_IN) _i10,
+             XF_PTNAME(DEPTH_IN) _i11,
+             XF_PTNAME(DEPTH_IN) _i12,
+             XF_PTNAME(DEPTH_IN) _i20,
+             XF_PTNAME(DEPTH_IN) _i21,
+             XF_PTNAME(DEPTH_IN) _i22,
+             XF_PTNAME(DEPTH_PHASE) angle,
+             uchar_t _low_threshold,
+             uchar_t _high_threshold) {
+    uchar_t NMS = 0;
+    int cmp1, cmp2;
+    if (_i11 > _low_threshold) {
+        if (angle == 0) {
+            cmp1 = _i10;
+            cmp2 = _i12;
+            if ((_i11 > cmp1) && (_i11 >= cmp2)) {
+                if (_i11 > _high_threshold) {
+                    if (EDGELINK)
+                        NMS = 3;
+                    else
+                        NMS = 0xff;
+                } else {
+                    if (EDGELINK)
+                        NMS = 1;
+                    else
+                        NMS = 0x80;
+                }
+            } else {
+                NMS = 0;
+            }
+        }
+        if (angle == 45) {
+            cmp1 = _i02;
+            cmp2 = _i20;
+            if ((_i11 > cmp1) && (_i11 > cmp2)) {
+                if (_i11 > _high_threshold) {
+                    if (EDGELINK)
+                        NMS = 3;
+                    else
+                        NMS = 0xff;
+
+                } else {
+                    if (EDGELINK)
+                        NMS = 1;
+                    else
+                        NMS = 0x80;
+                }
+            } else {
+                NMS = 0;
+            }
+        }
+        if (angle == 90) {
+            cmp1 = _i01;
+            cmp2 = _i21;
+            if ((_i11 > cmp1) && (_i11 >= cmp2)) {
+                if (_i11 > _high_threshold) {
+                    if (EDGELINK)
+                        NMS = 3;
+                    else
+                        NMS = 0xff;
+
+                } else {
+                    if (EDGELINK)
+                        NMS = 1;
+                    else
+                        NMS = 0x80;
+                }
+            } else {
+                NMS = 0;
+            }
+        }
+        if (angle == 135) {
+            cmp1 = _i00;
+            cmp2 = _i22;
+            if ((_i11 > cmp1) && (_i11 > cmp2)) {
+                if (_i11 > _high_threshold) {
+                    if (EDGELINK)
+                        NMS = 3;
+                    else
+                        NMS = 0xff;
+
+                } else {
+                    if (EDGELINK)
+                        NMS = 1;
+                    else
+                        NMS = 0x80;
+                }
+            } else {
+                NMS = 0;
+            }
+        }
+    } else {
+        NMS = 0;
+    }
+    return NMS;
+}
