+             uint16_t imgheight,
+             uint16_t imgwidth) {
+// clang-format off
+    #pragma HLS inline
+    // clang-format on
+    imgwidth = imgwidth >> XF_BITSHIFT(NPC);
+    xFAngleKernel<SRC_T, DST_T, ROWS, COLS, DEPTH_SRC, DEPTH_DST, NPC, WORDWIDTH_SRC, WORDWIDTH_DST,
+                  (COLS >> XF_BITSHIFT(NPC)), TC1>(_src1, _src2, _dst, imgheight, imgwidth);
+}
