+    for (uint16_t row = 0; row < img_height; row++) {
+// clang-format off
+    #pragma HLS LOOP_TRIPCOUNT max = ROWS
+        // clang-format on
+        for (uint16_t col = 0; col < img_width; col++) {
+// clang-format off
