+            for (int k = 0; k < MAXCOLOR; k++) {
+                for (int i = 0; i < XF_CHANNELS(SRC_T, NPC); i++) {
+                    _lower_thresh[i] = (XF_PTNAME(DEPTH_DST))low_thresh[k][i];
+                    _upper_thresh[i] = (XF_PTNAME(DEPTH_DST))high_thresh[k][i];
