+
+#ifndef __cplusplus
+#error C++ is needed to include this header
+#endif
+
+typedef unsigned short uint16_t;
+typedef unsigned char uchar;
+
+#include "hls_stream.h"
+#include "../common/xf_common.hpp"
+#include "../common/xf_utility.hpp"
